import { memo } from 'react'
import styled, { css } from 'styled-components'

import { toCurrency } from '../../../../helpers'
import { Body } from '../../../../components/typography/Body'
import { Heading } from '../../../../components/typography/Heading'

const Container = styled.div<{ $isHighlighted: boolean }>(
  ({ theme: { boxShadow, color, borderRadius } }) => css`
    padding: 1.5rem;
    border-radius: ${borderRadius.xs};
    transition: box-shadow 0.1s ease-in;
    position: relative;
    background: ${color.foodItemBackground};

    &:hover {
      cursor: pointer;
      box-shadow: ${boxShadow.card};
    }
  `
)

const Quantity = styled(Body)(
  ({ theme: { color, borderRadius } }) => css`
    padding: 0.25rem;
    width: 35px;
    height: 35px;
    border-radius: ${borderRadius.xs};
    display: flex;
    align-items: center;
    justify-content: center;
    background: ${color.black};
    color: ${color.white};
    position: absolute;
    top: 0;
    right: 0;
  `
)

const Description = styled(Body)(
  ({ theme: { color } }) => `
  margin: 0;
  color: ${color.badgeText};
  margin-top: 0.5rem;
`
)

const Price = styled(Body)`
  margin: 0;
  margin-top: 1rem;
`

type FoodItemProps = {
  quantity?: number
  name: string
  price: number
  description?: string
  onClick: () => void
}

export const FoodItem = memo(
  ({ quantity = 0, name, price, description, onClick }: FoodItemProps) => (
    <Container $isHighlighted={quantity > 0} onClick={onClick}>
      <div>
        {quantity > 0 && (
          <Quantity aria-label="food quantity" type="span" fontWeight="medium">
            {quantity}
          </Quantity>
        )}
        <Heading level={4}>{name}</Heading>
        <Description>{description}</Description>
        <Price>{toCurrency(price)}</Price>
      </div>
    </Container>
  )
)
FoodItem.displayName = 'FoodItem'

import styled from 'styled-components'
import { useNavigate } from 'react-router-dom'
import Carousel, { type ArrowProps, type CarouselProps } from 'react-multi-carousel'

import { useFetchRestaurants } from '../../../../api/hooks'
import { IconButton } from '../../../../components/IconButton'
import { PageSection } from '../../../../components/PageSection'
import { RestaurantCard, RestaurantCardSkeleton } from '../../../../components/RestaurantCard'
import { Restaurant } from '../../../../types'
import { isMobile } from '../../../../helpers'

const PreviousButton = styled(IconButton)`
  position: absolute;
  left: 0;
`

const NextButton = styled(IconButton)`
  position: absolute;
  right: 0;
`

type RestaurantsSectionProps = {
  title: string
}

const CustomArrow = (props: Partial<CarouselProps & ArrowProps> & { isNext?: boolean }) => {
  // filter out unnecessary props coming from react-multi-carousel
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { carouselState, rtl, isNext, ...rest } = props
  return isNext ? (
    <NextButton name="arrow-right" {...rest} />
  ) : (
    <PreviousButton name="arrow-left" {...rest} />
  )
}

export const RestaurantsSection = ({ title }: RestaurantsSectionProps) => {
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurants()

  const isOnMobile = isMobile()
  return (
    <PageSection title={title}>
      <Carousel
        draggable={isOnMobile}
        partialVisible={isOnMobile}
        customLeftArrow={<CustomArrow />}
        customRightArrow={<CustomArrow isNext />}
        responsive={{
          desktop: {
            breakpoint: { max: 5000, min: 1024 },
            items: 3,
            slidesToSlide: 3,
          },
          tablet: {
            breakpoint: { max: 1024, min: 464 },
            items: 2,
            paritialVisibilityGutter: 50,
          },
          mobile: {
            breakpoint: { max: 464, min: 0 },
            items: 1,
            paritialVisibilityGutter: 30,
          },
        }}
        containerClass="carousel-container"
        removeArrowOnDeviceType={['tablet', 'mobile']}
        itemClass="carousel-item"
      >
        {status === 'loading'
          ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
          : restaurants.map((restaurant: Restaurant, index: number) => (
              <RestaurantCard
                key={restaurant.name + index}
                {...restaurant}
                onClick={() => navigate(`/restaurants/${restaurant.id}`)}
              />
            ))}
      </Carousel>
    </PageSection>
  )
}

import { mergeConfig, defineConfig, coverageConfigDefaults } from 'vitest/config'
import viteConfig from './vite.config'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import { storybookTest } from '@storybook/addon-vitest/vitest-plugin'
import { playwright } from '@vitest/browser-playwright'

const dirname =
  typeof __dirname !== 'undefined' ? __dirname : path.dirname(fileURLToPath(import.meta.url))
const playwrightProviderOptions =
  process.env.STORYBOOK_TEST_SCREENSHOTS === 'true'
    ? {
        contextOptions: {
          deviceScaleFactor: 2,
          viewport: { width: 393, height: 852 },
          isMobile: true,
          hasTouch: true,
          userAgent:
            'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.0 Mobile/15E148 Safari/604.1',
        },
      }
    : {}

// More info at: https://storybook.js.org/docs/next/writing-tests/integrations/vitest-addon
export default mergeConfig(
  viteConfig,
  defineConfig({
    test: {
      coverage: {
        exclude: [
          ...coverageConfigDefaults.exclude,
          'storybook.setup.ts',
          '**/*.stories.*',
          '.storybook',
          'src/docs',
          'src/components/Button/utils.tsx',
          'build',
          'public',
          'functions',
          '**/conditional-logic.ts',
          '**/RestaurantCard/progress',
          '**/RestaurantsSection.container.tsx',
          'src/stub',
          'ps-setup.ts',
          '**/serviceWorker.ts',
        ],
      },
      projects: [
        {
          extends: true,
          test: {
            name: 'node',
            environment: 'happy-dom',
            include: ['**/*.test.ts'],
          },
        },
        {
          extends: true,
          plugins: [
            // The plugin will run tests for the stories defined in your Storybook config
            // See options at:
            // https://storybook.js.org/docs/next/writing-tests/integrations/vitest-addon#storybooktest
            storybookTest({
              configDir: path.join(dirname, '.storybook'),
            }),
          ],
          test: {
            name: 'storybook',
            browser: {
              enabled: true,
              headless: true,
              provider: playwright(playwrightProviderOptions),
              instances: [{ browser: 'chromium' }],
            },
          },
        },
      ],
    },
  })
)

