      // RestaurantDetailPage uses useParams to get the id
      // We need to provide route context with a valid id
      return <Story />
    },
  ],
  play: async ({ canvas }) => {
    // The page fetches restaurant data via MSW - wait for it to load
    await waitFor(
      () => {
        expect(canvas.getByText('Pizza Palace')).toBeVisible()
      },
      { timeout: 5000 }
    )
    await expect(canvas.getByText(/specialties/i)).toBeVisible()
  },
}

